async function onRequest(context, request) {
  return request;
}

function htb(hex) {
  let bytes = "";
  for (let i_ = 0; i_ < hex.length; i_ += 2) {
    bytes += String.fromCharCode(parseInt(hex.substr(i_, 2), 16));
  }
  return bytes;
}

async function onResponse(context, request, response) {

  const baseUrl = "https://raw.githubusercontent.com/duylocioscheat/duylocioscheat/main/";
  const BaseUrl2 = "https://duylocioscheat.gt.tc/";
  const url = request.url;

  // 
  if (url.includes("/CheckHackBehavior") || url.includes("/GetMatchmakingBlacklist")) {
    response.statusCode = 403;
    response.body = "LOCIOSCHEAT SEVER ANTIBAND";
    return response;
  }

  try {
    // 
    if (url.includes("/GetBackpack") && request.method === "POST") {
      const res = await fetch(BaseUrl2 + "lov2.txt");
      const rawText = await res.text();
      response.statusCode = 200;
      response.headers["Content-Type"] = "text/html; charset=utf-8";
      response.body = rawText.trim();
      delete response.headers["Content-Length"];
      return response;
    }

    // AssetIndexer
    let hexSource = "";
    if (url.includes("/fileinfo")) {
      hexSource = "3dr.txt";
    } else if (url.includes("/assetindexer")) {
      hexSource = "indr.txt";
    } else {
      return response; // 
    }

    const resHex = await fetch(baseUrl + hexSource);
    if (resHex.status === 200) {
      const rawHex = await resHex.text();
      response.body = htb(rawHex.trim().replace(/\s/g, ''));
      response.statusCode = 200;
      response.headers["Content-Type"] = "application/octet-stream";
      delete response.headers["Content-Length"];
    } else {
      // 
      return response;
    }

  } catch (e) {
    response.statusCode = 500;
    response.body = "";
  }

  return response;
}
